async function getGames() {
    const groups = [
        35767078,
        921325898
    ];
    let games = [];
    for (const groupId of groups){
        const gamesRes = await fetch(`https://games.roblox.com/v2/groups/${groupId}/games?accessFilter=Public&limit=50&sortOrder=Asc`, {
            cache: "no-store"
        });
        const gamesData = await gamesRes.json();
        const universeIds = gamesData.data.map((game)=>game.id);
        if (universeIds.length > 0) {
            // THUMBNAILS
            const thumbRes = await fetch(`https://thumbnails.roblox.com/v1/games/multiget/thumbnails?universeIds=${universeIds.join(",")}&size=768x432&format=Png`);
            const thumbData = await thumbRes.json();
            // GAME STATS
            const statsRes = await fetch(`https://games.roblox.com/v1/games?universeIds=${universeIds.join(",")}`);
            const statsData = await statsRes.json();
            for (const thumb of thumbData.data){
                const gameInfo = statsData.data.find((g)=>g.id === thumb.universeId);
                if (thumb.thumbnails?.[0]?.imageUrl) {
                    games.push({
                        image: thumb.thumbnails[0].imageUrl,
                        name: gameInfo?.name || "Game",
                        visits: gameInfo?.visits || 0,
                        players: gameInfo?.playing || 0,
                        placeId: gameInfo?.rootPlaceId
                    });
                }
            }
        }
    }
    return games;
}
